class SecureErrorHandler:
    """Handles errors securely based on environment"""
    
    def __init__(self, environment=Environment.PRODUCTION):
        self.environment = environment
        self.is_debug_mode = environment != Environment.PRODUCTION
    
    def sanitize_error_message(self, error):
        """Remove sensitive information from error messages"""
        error_str = str(error)
        
        # Remove potential sensitive patterns
        sensitive_patterns = [
            'password', 'token', 'secret', 'api_key', 'apikey',
            'authorization', 'credential', 'private_key', 'session'
        ]
        
        error_lower = error_str.lower()
        for pattern in sensitive_patterns:
            if pattern in error_lower:
                return "An internal error occurred. Error details have been logged."
        
        return error_str
    
    def get_safe_traceback(self):
        """Get traceback with sensitive info removed"""
        if not self.is_debug_mode:
            return None
        
        tb_lines = traceback.format_exc().split('\n')
        safe_lines = []
        
        for line in tb_lines:
            # Skip lines that might contain file paths with sensitive info
            if '/home/' in line or 'C:\\Users\\' in line:
                line = line.split('File')[0] + 'File "<sanitized>"'
            safe_lines.append(line)
        
        return '\n'.join(safe_lines)
    
    def create_error_details(self, error, context_info=None):
        """Create safe error details for client"""
        details = {
            'error_type': type(error).__name__,
            'message': self.sanitize_error_message(error)
        }
        
        if self.is_debug_mode:
            safe_tb = self.get_safe_traceback()
            if safe_tb:
                details['traceback'] = safe_tb
            
            if context_info:
                # Only include non-sensitive context
                safe_context = self._sanitize_context(context_info)
                if safe_context:
                    details['context'] = safe_context
        
        return details
    
    def _sanitize_context(self, context_info):
        """Remove sensitive data from context"""
        if not isinstance(context_info, dict):
            return {}
        
        safe_context = {}
        sensitive_keys = {
            'password', 'token', 'secret', 'api_key', 'apikey',
            'authorization', 'credential', 'private_key', 'session',
            'cookie', 'auth', 'jwt'
        }
        
        for key, value in context_info.items():
            key_lower = key.lower()
            if any(sensitive in key_lower for sensitive in sensitive_keys):
                safe_context[key] = '<redacted>'
            elif isinstance(value, (str, int, float, bool)):
                safe_context[key] = value
            elif isinstance(value, (list, dict)):
                safe_context[key] = '<complex_type>'
            else:
                safe_context[key] = '<object>'
        
        return safe_context
    
    def format_error_message(self, details):
        """Format error details into a string message"""
        if self.is_debug_mode:
            msg_parts = [f"Error: {details['error_type']}"]
            msg_parts.append(f"Message: {details['message']}")
            
            if 'context' in details:
                msg_parts.append(f"Context: {details['context']}")
            
            if 'traceback' in details:
                msg_parts.append(f"Traceback:\n{details['traceback']}")
            
            return '\n'.join(msg_parts)
        else:
            return f"An error occurred: {details['message']}"


